const _errLog=[];
const _origConsoleError=console.error.bind(console);
console.error=function(...args){_origConsoleError(...args);_captureError(args.map(a=>a instanceof Error?a.message+'\n'+a.stack:String(a)).join(' '));};
window.onerror=function(msg,src,line,col,err){_captureError(`${msg}\nat ${src}:${line}:${col}${err?.stack?'\n'+err.stack:''}`);};
window.onunhandledrejection=function(e){_captureError('Unhandled promise: '+(e.reason?.message||e.reason||'unknown'));};
function _captureError(msg){const t=new Date().toLocaleTimeString();_errLog.push({time:t,msg});if(_errLog.length>50)_errLog.shift();const badge=document.getElementById('errlog-badge');if(badge)badge.classList.add('has-errors');const body=document.getElementById('errlog-body');if(body&&body.querySelector('.errlog-empty'))body.innerHTML='';if(body){const entry=document.createElement('div');entry.className='errlog-entry';entry.innerHTML=`<div class="errlog-time">${t}</div><div class="errlog-msg">${msg.replace(/</g,'&lt;')}</div>`;body.appendChild(entry);body.scrollTop=body.scrollHeight;}}
function toggleErrLog(){const o=document.getElementById('errlog-overlay');o.classList.toggle('active');}

