document.addEventListener('DOMContentLoaded',async()=>{
  // Load chrome.storage into _store
  const storageData = await chrome.storage.local.get(null);
  Object.assign(_store, storageData);

  // (no service worker in extension)
  const urlSheet=null;
  
  const tok=ls('focus_token'),exp=parseInt(ls('focus_token_expiry')||'0');
  if(tok&&exp>Date.now()){
    S.token=tok;S.tokenExpiry=exp;S.spreadsheetId=urlSheet||ls('focus_spreadsheet_id');S.mode=ls('focus_mode')||'work';
    S.ignition={personal:ls('focus_ign_p')||'',work:ls('focus_ign_w')||''};
    if(!S.spreadsheetId){showMain();setupSheet();}
    else{showMain();applyMode(S.mode,false);await loadTags();await ensureNotesSheet();await loadStats();checkIgnition();}
  }
});

