// ── AUTH ──────────────────────────────────
function startLogin(){
  chrome.runtime.sendMessage({action:'login'}, (resp) => {
    if(chrome.runtime.lastError){showLoginError(chrome.runtime.lastError.message);return;}
    if(resp && resp.error){showLoginError(resp.error);return;}
    if(resp && resp.token){
      S.token=resp.token;S.tokenExpiry=resp.expiry;
      lss('focus_token',resp.token);lss('focus_token_expiry',resp.expiry);
      S.spreadsheetId=ls('focus_spreadsheet_id');
      S.mode=ls('focus_mode')||'work';
      S.ignition={personal:ls('focus_ign_p')||'',work:ls('focus_ign_w')||''};
      showMain();applyMode(S.mode,false);
      if(!S.spreadsheetId)setupSheet();
      else loadTags().then(()=>ensureNotesSheet()).then(()=>{loadStats();checkIgnition();});
    }
  });
}
