async function connectExistingSheet(){const id=document.getElementById('sheet-id-field').value.trim();if(!id){showLoginError('Paste your Sheet ID');return;}if(!S.token||S.tokenExpiry<=Date.now()){lss('focus_pending_sheet',id);startLogin();return;}lss('focus_spreadsheet_id',id);S.spreadsheetId=id;showMain();applyMode(S.mode,false);await loadTags();loadStats();checkIgnition();}
function showLoginError(m){const e=document.getElementById('login-error');e.textContent=m;e.style.display='block';}
async function sf(url,opts={}){if(!S.token){showToast('Not signed in');throw new Error('No auth token');}if(S.tokenExpiry&&Date.now()>=S.tokenExpiry){showToast('Session expired — signing in again…');lss('focus_token','');lss('focus_token_expiry','');setTimeout(()=>startLogin(),1200);throw new Error('Token expired');}let r;for(let _try=0;_try<3;_try++){try{r=await fetch(url,{...opts,headers:{'Authorization':`Bearer ${S.token}`,'Content-Type':'application/json',...(opts.headers||{})}});break;}catch(netErr){if(_try<2){await new Promise(w=>setTimeout(w,(_try+1)*1500));continue;}const msg='Network error: '+netErr.message;showToast(msg);throw new Error(msg);}}if(!r.ok){const e=await r.json().catch(()=>({}));const msg=e.error?.message||`API error ${r.status}`;if(r.status===401){showToast('Session expired — signing in again…');lss('focus_token','');lss('focus_token_expiry','');setTimeout(()=>startLogin(),1200);throw new Error(msg);}if(r.status===403){showToast('Permission denied: '+msg);}else if(!msg.includes('Unable to parse range')){showToast('API error: '+msg);}throw new Error(msg);}return r.json();}
async function findSheetInDrive(){showToast('Searching Drive for existing sheet…');try{const q=encodeURIComponent("name='Focus — Signal & Noise Tasks' and mimeType='application/vnd.google-apps.spreadsheet' and trashed=false");const r=await sf(`https://www.googleapis.com/drive/v3/files?q=${q}&fields=files(id,name,modifiedTime)&orderBy=modifiedTime desc&pageSize=5`);if(r.files&&r.files.length>0){const found=r.files[0];S.spreadsheetId=found.id;lss('focus_spreadsheet_id',found.id);showToast(`Found your sheet! (${r.files.length} match${r.files.length>1?'es':''})`);return true;}}catch(e){console.error('Drive search failed:',e);showToast('Drive search failed, creating new sheet…');}return false;}
async function setupSheet(){const found=await findSheetInDrive();if(found){applyMode(S.mode,false);await loadTags();await loadStats();checkIgnition();return;}showToast('Creating new sheet…');try{const r=await sf(SHEETS,{method:'POST',body:JSON.stringify({properties:{title:'Focus — Signal & Noise Tasks'},sheets:[{properties:{sheetId:0,title:'Tasks'}},{properties:{sheetId:1,title:'Weekly Review'}},{properties:{sheetId:2,title:'Tags'}},{properties:{sheetId:3,title:'Notes'}}]})});S.spreadsheetId=r.spreadsheetId;lss('focus_spreadsheet_id',S.spreadsheetId);await sf(`${SHEETS}/${S.spreadsheetId}/values/Tasks!A1:N1?valueInputOption=RAW`,{method:'PUT',body:JSON.stringify({values:[['task_id','task_name','category','signal_or_noise','status','due_date','comment','reason','source','created_date','week_number','days_open','closed_date','tags']]})});const tr=DEFAULT_TAGS.map((n,i)=>[n,TAG_PALETTE[i%TAG_PALETTE.length]]);await sf(`${SHEETS}/${S.spreadsheetId}/values/Weekly Review!A1:N1?valueInputOption=RAW`,{method:'PUT',body:JSON.stringify({values:[['week_number','year','signals_captured','signals_done','noise_captured','noise_done','ignored','delegated','completion','focus_score','streak','reflect_ratio','reflect_hard','reflect_next']]})});await sf(`${SHEETS}/${S.spreadsheetId}/values/Tags!A1:B1?valueInputOption=RAW`,{method:'PUT',body:JSON.stringify({values:[['tag_name','color']]})});await sf(`${SHEETS}/${S.spreadsheetId}/values/Tags!A2:B?valueInputOption=RAW&insertDataOption=INSERT_ROWS`,{method:'POST',body:JSON.stringify({values:tr})});await sf(`${SHEETS}/${S.spreadsheetId}/values/Notes!A1:F1?valueInputOption=RAW`,{method:'PUT',body:JSON.stringify({values:[['note_id','text','category','status','created_date','promoted_to_task_id']]})});showToast('Sheet created!');await loadTags();loadStats();checkIgnition();}catch(e){showToast('Error: '+e.message);}}

