async function loadTags(){try{const r=await sf(`${SHEETS}/${S.spreadsheetId}/values/Tags!A2:B`);const rows=r.values||[];S.tags=rows.map((r,i)=>({name:r[0]||'',color:r[1]||TAG_PALETTE[i%TAG_PALETTE.length]})).filter(t=>t.name);if(!S.tags.length)S.tags=DEFAULT_TAGS.map((n,i)=>({name:n,color:TAG_PALETTE[i%TAG_PALETTE.length]}));}catch(e){if(e.message&&e.message.includes('Unable to parse range')){try{await sf(`https://sheets.googleapis.com/v4/spreadsheets/${S.spreadsheetId}:batchUpdate`,{method:'POST',body:JSON.stringify({requests:[{addSheet:{properties:{title:'Tags'}}}]})});const tr=DEFAULT_TAGS.map((n,i)=>[n,TAG_PALETTE[i%TAG_PALETTE.length]]);await sf(`${SHEETS}/${S.spreadsheetId}/values/Tags!A1:B?valueInputOption=RAW`,{method:'PUT',body:JSON.stringify({values:[['tag_name','color'],...tr]})});showToast('Tags tab created!');}catch(_){}}S.tags=DEFAULT_TAGS.map((n,i)=>({name:n,color:TAG_PALETTE[i%TAG_PALETTE.length]}));}renderCapTags();}
function renderCapTags(){const w=document.getElementById('cap-tags');if(!w)return;w.innerHTML='';S.tags.forEach(t=>{const c=div('tag-chip'+(S.capTags.includes(t.name)?' selected':''));c.textContent=t.name;c.style.cssText=`color:${t.color};border-color:${t.color}40`;c.addEventListener('click',()=>{const i=S.capTags.indexOf(t.name);if(i>=0)S.capTags.splice(i,1);else S.capTags.push(t.name);renderCapTags();});w.appendChild(c);});}
const TAG_GLYPHS={'Health':`<svg width="10" height="10" viewBox="0 0 12 12" fill="none"><polyline points="1,6 3,6 4.5,3 6,9 7.5,6 9,6 11,6" stroke="currentColor" stroke-width="1" stroke-linecap="round" stroke-linejoin="round"/></svg>`,'Cases':`<svg width="10" height="10" viewBox="0 0 12 12" fill="none"><rect x="1.5" y="1.5" width="9" height="9" rx="1" stroke="currentColor" stroke-width="1"/><circle cx="6" cy="6" r="1" fill="currentColor"/></svg>`,'Risk Assessment':`<svg width="10" height="10" viewBox="0 0 12 12" fill="none"><path d="M6 1.5L11 10.5H1Z" stroke="currentColor" stroke-width="1" stroke-linejoin="round" fill="none"/><line x1="6" y1="4.5" x2="6" y2="7.5" stroke="currentColor" stroke-width="1"/></svg>`,'Side-job':`<svg width="10" height="10" viewBox="0 0 12 12" fill="none"><polygon points="6,1 7.5,4.5 11,4.5 8.25,7 9.5,11 6,8.5 2.5,11 3.75,7 1,4.5 4.5,4.5" stroke="currentColor" stroke-width="1" stroke-linejoin="round" fill="none"/></svg>`,'Learning':`<svg width="10" height="10" viewBox="0 0 12 12" fill="none"><path d="M3 8L6 2L9 8" stroke="currentColor" stroke-width="1" stroke-linecap="round" stroke-linejoin="round"/><line x1="6" y1="8" x2="6" y2="11" stroke="currentColor" stroke-width="1" stroke-linecap="round"/></svg>`,'Clara':`<svg width="10" height="10" viewBox="0 0 12 12" fill="none"><circle cx="6" cy="6" r="4" stroke="currentColor" stroke-width="1" stroke-dasharray="2 1.5"/></svg>`,'Family':`<svg width="10" height="10" viewBox="0 0 12 12" fill="none"><circle cx="4" cy="3.5" r="1.5" stroke="currentColor" stroke-width="1"/><circle cx="8" cy="3.5" r="1.5" stroke="currentColor" stroke-width="1"/><path d="M1 10c0-2 1.5-3.5 3-3.5s3 1.5 3 3.5M5 10c0-2 1.5-3.5 3-3.5s3 1.5 3 3.5" stroke="currentColor" stroke-width="1" stroke-linecap="round" fill="none"/></svg>`,'Admin':`<svg width="10" height="10" viewBox="0 0 12 12" fill="none"><circle cx="6" cy="6" r="4.5" stroke="currentColor" stroke-width="1"/><path d="M6 3v3l2 1.5" stroke="currentColor" stroke-width="1" stroke-linecap="round"/></svg>`,'Idea development':`<svg width="10" height="10" viewBox="0 0 12 12" fill="none"><circle cx="6" cy="5" r="3" stroke="currentColor" stroke-width="1"/><line x1="5" y1="9" x2="7" y2="9" stroke="currentColor" stroke-width="1" stroke-linecap="round"/><line x1="5" y1="10.5" x2="7" y2="10.5" stroke="currentColor" stroke-width="1" stroke-linecap="round"/><line x1="6" y1="8" x2="6" y2="9" stroke="currentColor" stroke-width="1"/></svg>`};
function makeTagHtml(tags){if(!tags?.length)return'';return tags.map(n=>{const t=S.tags.find(x=>x.name===n);const c=t?t.color:'#888';const g=TAG_GLYPHS[n]||'';return`<span class="task-tag-pwa" style="background:${c}0a;color:${c};border-color:${c}25" data-tag="${esc(n)}">${g?g+' ':''}${esc(n)}</span>`;}).join('');}

// ── TASKS ──────────────────────────────────
async function readTasks(){const r=await sf(`${SHEETS}/${S.spreadsheetId}/values/Tasks!A2:N`);return(r.values||[]).map((r,i)=>({task_id:r[0]||'',task_name:r[1]||'',category:r[2]||'personal',signal_or_noise:r[3]||'signal',status:r[4]||'open',due_date:r[5]||'',comment:r[6]||'',reason:r[7]||'',source:r[8]||'manual',created_date:r[9]||'',week_number:r[10]||'',days_open:parseInt(r[11])||0,closed_date:r[12]||'',tags:r[13]?r[13].split(',').map(t=>t.trim()).filter(Boolean):[],_row:i})).filter(t=>t.status!=='deleted');}
async function getCachedTasks(force=false){if(!force&&S.tasks.length&&Date.now()-S._tasksCacheTime<TASK_CACHE_TTL)return S.tasks;S.tasks=await readTasks();S._tasksCacheTime=Date.now();return S.tasks;}
function invalidateTaskCache(){S._tasksCacheTime=0;}
async function appendTask(t){t.task_id='task_'+Date.now()+'_'+Math.random().toString(36).slice(2,7);t.created_date=todayStr();t.week_number=weekNum();t.days_open=0;t.source='extension';t.closed_date='';t.tags=t.tags||[];await sf(`${SHEETS}/${S.spreadsheetId}/values/Tasks!A:N:append?valueInputOption=RAW&insertDataOption=INSERT_ROWS`,{method:'POST',body:JSON.stringify({values:[[t.task_id,t.task_name,t.category,t.signal_or_noise,t.status,t.due_date,t.comment,t.reason||'',t.source,t.created_date,t.week_number,t.days_open,t.closed_date,(t.tags||[]).join(', ')]]})});}
async function updateTask(t){const row=t._row+2;t.days_open=Math.max(0,Math.floor((Date.now()-new Date(t.created_date))/86400000));if(['done','delegated','ignored'].includes(t.status)&&!t.closed_date)t.closed_date=todayStr();await sf(`${SHEETS}/${S.spreadsheetId}/values/Tasks!A${row}:N${row}?valueInputOption=RAW`,{method:'PUT',body:JSON.stringify({values:[[t.task_id,t.task_name,t.category,t.signal_or_noise,t.status,t.due_date,t.comment,t.reason||'',t.source,t.created_date,t.week_number,t.days_open,t.closed_date,(t.tags||[]).join(', ')]]})});}
async function loadStats(){try{S.tasks=await getCachedTasks();updateStats();}catch(e){console.error('loadStats failed:',e);showToast('Failed to load: '+e.message);}}
async function loadTasksScreen(){document.getElementById('tasks-list').innerHTML='<div class="loading-text">Loading…</div>';const tv=ls('focus_ticker_visible');const tw=document.getElementById('ticker-wrap'),tb=document.getElementById('ticker-toggle');if(tv==='1'){tw.style.display='';tb.textContent='hide timeline';}else{tw.style.display='none';tb.textContent='show timeline';}try{S.tasks=await getCachedTasks();updateStats();renderTicker();renderTasks();checkDecay();}catch(e){document.getElementById('tasks-list').innerHTML=`<div class="empty-state"><strong>Error</strong>${e.message}</div>`;}}
async function refreshAll(){showToast('Refreshing…');try{await loadTags();S.tasks=await getCachedTasks(true);updateStats();if(document.querySelector('[data-s="tasks"].active'))renderTicker(),renderTasks();renderCapTags();showToast('Updated');}catch(e){console.error('Refresh failed:',e);showToast('Refresh failed: '+e.message);}}

function updateStats(){const cat=S.tasks.filter(t=>t.category===S.mode);const open=cat.filter(t=>['open','in_progress'].includes(t.status));const done=cat.filter(t=>t.status==='done');const sigs=open.filter(t=>t.signal_or_noise==='signal').length,nois=open.filter(t=>t.signal_or_noise==='noise').length;const ratio=fmtRatio(sigs,nois);document.getElementById('ts-sig').textContent=sigs;document.getElementById('ts-noi').textContent=nois;document.getElementById('ts-done').textContent=done.length;document.getElementById('ts-ratio').textContent=ratio;document.getElementById('sb-sig').textContent=sigs+' signals';document.getElementById('sb-noi').textContent=nois+' noise';document.getElementById('sb-ratio').textContent='ratio '+ratio;}

function renderTicker(){const wrap=document.getElementById('ticker-wrap'),ticker=document.getElementById('chrono-ticker');ticker.innerHTML='';const open=S.tasks.filter(t=>t.category===S.mode&&['open','in_progress'].includes(t.status));open.sort((a,b)=>{if(a.due_date&&b.due_date)return new Date(a.due_date)-new Date(b.due_date);if(a.due_date&&!b.due_date)return-1;if(!a.due_date&&b.due_date)return 1;return new Date(a.created_date)-new Date(b.created_date);});if(!open.length){wrap.classList.add('empty');return;}wrap.classList.remove('empty');open.forEach(task=>{const c=div(`ticker-card ${task.signal_or_noise}`);const dd=task.due_date?Math.ceil((new Date(task.due_date)-new Date())/86400000):null;const dt=dd!==null?(dd<=0?'due today':`${dd}d`):`${daysAgo(task.created_date)}d open`;c.innerHTML=`<div class="ticker-type">${task.signal_or_noise==='signal'?'▲':'~'}</div><div class="ticker-name">${esc(task.task_name)}</div><div class="ticker-due${dd!==null&&dd<=1?' urgent':''}">${dt}</div>`;ticker.appendChild(c);});}

function renderTasks(){const list=document.getElementById('tasks-list');list.innerHTML='';const q=(document.getElementById('task-search')?.value||'').toLowerCase().trim();const cat=S.tasks.filter(t=>t.category===S.mode&&['open','in_progress'].includes(t.status)&&(!q||t.task_name.toLowerCase().includes(q)||(t.tags||[]).some(tg=>tg.toLowerCase().includes(q))));const f=S.filter;const sigs=cat.filter(t=>t.signal_or_noise==='signal'&&(f==='all'||f==='signal'));const nois=cat.filter(t=>t.signal_or_noise==='noise'&&(f==='all'||f==='noise'));const allDone=S.tasks.filter(t=>t.category===S.mode&&t.status==='done'&&(!q||t.task_name.toLowerCase().includes(q)));const sevenDaysAgo=new Date();sevenDaysAgo.setDate(sevenDaysAgo.getDate()-7);const sevenStr=sevenDaysAgo.toISOString().split('T')[0];const recentDone=allDone.filter(t=>t.closed_date&&t.closed_date>=sevenStr);const olderDone=allDone.length-recentDone.length;if(!cat.length&&!allDone.length){list.innerHTML='<div class="empty-state"><strong>All clear</strong>Nothing open. Capture a signal.</div>';return;}if(sigs.length){if(f==='all'){const l=div('section-lbl');l.textContent='Signals';list.appendChild(l);}sigs.forEach((t,i)=>list.appendChild(buildItem(t,false,i,sigs.length)));}if(nois.length){if(f==='all'){const l=div('section-lbl');l.textContent='Noise';list.appendChild(l);}nois.forEach((t,i)=>list.appendChild(buildItem(t,false,i,nois.length)));}if(recentDone.length&&f==='all'){const l=div('section-lbl');l.textContent='Done (last 7 days)';list.appendChild(l);const doneWrap=div('section-done-list');recentDone.forEach(t=>doneWrap.appendChild(buildItem(t,true,0,0)));list.appendChild(doneWrap);if(olderDone>0&&!S.showAllDone){const more=div('');more.style.cssText='text-align:center;padding:8px;font-size:11px;font-family:var(--mono);color:var(--smoke);cursor:pointer';more.textContent=`+ ${olderDone} older done tasks`;more.addEventListener('click',()=>{S.showAllDone=true;renderTasks();});list.appendChild(more);}if(S.showAllDone&&olderDone>0){const olderTasks=allDone.filter(t=>!t.closed_date||t.closed_date<sevenStr);const l2=div('section-lbl');l2.textContent='Older';list.appendChild(l2);const doneWrap2=div('section-done-list');olderTasks.forEach(t=>doneWrap2.appendChild(buildItem(t,true,0,0)));list.appendChild(doneWrap2);}}const total=allDone.length+cat.length;document.getElementById('prog-fill').style.width=(total?Math.round((allDone.length/total)*100):0)+'%';document.getElementById('prog-label').textContent=`${allDone.length} of ${total} done`;setTimeout(()=>{applyDecay();if(S.activeTagFilter)applyTagFilter(S.activeTagFilter,true);},20);}
function onTaskSearch(){renderTasks();}

function buildItem(task,isDone,idx,total){try{const dd=task.due_date?Math.ceil((new Date(task.due_date)-new Date())/86400000):null;const dueTag=dd!==null?(dd<=0?`<span class="tag due">due today</span>`:`<span class="tag muted">due ${fmtDate(task.due_date)}</span>`):'';const canUp=!isDone&&idx>0,canDn=!isDone&&idx<total-1;const item=div(`task-item ${task.signal_or_noise}${isDone?' done':''}`);item.dataset.id=task.task_id;const editBtn=!isDone?`<button class="task-edit-btn" data-edit="1">&#9998;</button>`:'';item.innerHTML=`<div class="task-main"><div class="task-check"><span class="check-tick">&#10003;</span></div><div class="task-body"><div class="task-name">${esc(task.task_name)}</div><div class="task-meta"><span class="tag ${task.signal_or_noise==='signal'?'sig':'noi'}">${task.signal_or_noise}</span>${dueTag}${makeTagHtml(task.tags)}</div></div>${!isDone?`<div class="task-actions">${editBtn}<button class="reorder-btn" ${canUp?'':'disabled'} data-dir="-1">&uarr;</button><button class="reorder-btn" ${canDn?'':'disabled'} data-dir="1">&darr;</button></div>`:''}</div>${!isDone?buildEditPanel(task):''}`;if(!isDone){const chk=item.querySelector('.task-check');if(chk)chk.addEventListener('click',()=>implode(task,item));}if(!isDone){const eb=item.querySelector('[data-edit]');if(eb)eb.addEventListener('click',e=>{e.stopPropagation();toggleEditPanel(item,task);});}item.querySelectorAll('.task-tag-pwa').forEach(chip=>{chip.style.cursor='pointer';chip.addEventListener('click',e=>{e.stopPropagation();applyTagFilter(chip.dataset.tag);});});if(!isDone)item.querySelectorAll('.reorder-btn').forEach(b=>b.addEventListener('click',e=>{e.stopPropagation();reorder(task,parseInt(b.dataset.dir));}));return item;}catch(e){console.error('buildItem error:',e,task);const item=div('task-item signal');item.innerHTML=`<div class="task-main"><div class="task-body"><div class="task-name">${esc(task?.task_name||'Error rendering task')}</div><div class="task-meta"><span class="tag due">${e.message}</span></div></div></div>`;return item;}}

function buildEditPanel(task){const tagChips=(S.tags||[]).map(t=>{const sel=task.tags?.includes(t.name);return`<span class="edit-tag-chip${sel?' selected':''}" data-tagname="${esc(t.name)}" style="color:${t.color};border-color:${sel?t.color+'40':'transparent'}">${esc(t.name)}</span>`;}).join('');return`<div class="edit-panel" data-panel="1"><div class="edit-inner"><div><div class="edit-field-label">Task name</div><input class="edit-input" data-field="name" value="${esc(task.task_name)}"></div><div><div class="edit-field-label">Signal or noise</div><div class="edit-sn-row"><button class="edit-sn-btn${task.signal_or_noise==='signal'?' active-sig':''}" data-sn="signal">▲ Signal</button><button class="edit-sn-btn${task.signal_or_noise==='noise'?' active-noi':''}" data-sn="noise">~ Noise</button></div></div><div><div class="edit-field-label">Category</div><div class="edit-sn-row"><button class="edit-cat-btn${task.category==='personal'?' active-cat':''}" data-cat="personal">Personal</button><button class="edit-cat-btn${task.category==='work'?' active-cat':''}" data-cat="work">Work</button></div></div><div><div class="edit-field-label">Due date</div><input type="date" class="edit-input" data-field="due" value="${task.due_date||''}"></div><div><div class="edit-field-label">Tags</div><div class="edit-tags-wrap">${tagChips}</div></div><div><div class="edit-field-label">Status note</div><textarea class="edit-note" data-field="note" rows="2" placeholder="What's happening with this task?">${esc(task.comment||'')}</textarea></div><div class="edit-actions"><button class="edit-cancel" onclick="closeAllEdits()">Cancel</button><button class="edit-delete" data-delid="${task.task_id}" style="background:rgba(239,68,68,.1);color:var(--danger);border-color:rgba(239,68,68,.2)">Delete</button><button class="edit-save" data-taskid="${task.task_id}">Save</button></div></div></div>`;}


function toggleEditPanel(item,task){const panel=item.querySelector('[data-panel]');if(!panel)return;const isOpen=panel.classList.contains('open');closeAllEdits();if(!isOpen){panel.classList.add('open');panel.querySelectorAll('.edit-sn-btn').forEach(b=>b.addEventListener('click',e=>{e.stopPropagation();panel.querySelectorAll('.edit-sn-btn').forEach(x=>{x.classList.remove('active-sig','active-noi');});b.classList.add(b.dataset.sn==='signal'?'active-sig':'active-noi');}));panel.querySelectorAll('.edit-cat-btn').forEach(b=>b.addEventListener('click',e=>{e.stopPropagation();panel.querySelectorAll('.edit-cat-btn').forEach(x=>x.classList.remove('active-cat'));b.classList.add('active-cat');}));panel.querySelectorAll('.edit-tag-chip').forEach(c=>c.addEventListener('click',e=>{e.stopPropagation();c.classList.toggle('selected');c.style.borderColor=c.classList.contains('selected')?c.style.color+'40':'transparent';}));const saveBtn=panel.querySelector('.edit-save');if(saveBtn)saveBtn.addEventListener('click',async e=>{e.stopPropagation();await saveTaskEdit(task,panel);});const delBtn=panel.querySelector('.edit-delete');if(delBtn)delBtn.addEventListener('click',async e=>{e.stopPropagation();await deleteTask(task);});}}

function closeAllEdits(){document.querySelectorAll('.edit-panel.open').forEach(p=>p.classList.remove('open'));}

async function saveTaskEdit(task,panel){const name=panel.querySelector('[data-field="name"]').value.trim();if(!name){showToast('Task name required');return;}task.task_name=name;const snBtn=panel.querySelector('.edit-sn-btn.active-sig,.edit-sn-btn.active-noi');if(snBtn)task.signal_or_noise=snBtn.dataset.sn;const catBtn=panel.querySelector('.edit-cat-btn.active-cat');if(catBtn)task.category=catBtn.dataset.cat;task.due_date=panel.querySelector('[data-field="due"]').value||'';task.tags=[];panel.querySelectorAll('.edit-tag-chip.selected').forEach(c=>task.tags.push(c.dataset.tagname));task.comment=panel.querySelector('[data-field="note"]').value||'';showToast('Saving…');try{invalidateTaskCache();await updateTask(task);await loadTasksScreen();showToast('Updated');}catch(e){showToast('Error: '+e.message);}}
async function deleteTask(task){if(!confirm('Delete this task permanently? This cannot be undone.'))return;showToast('Deleting…');try{task.status='deleted';task.reason='Deleted by user';invalidateTaskCache();await updateTask(task);await loadTasksScreen();showToast('Task deleted');}catch(e){showToast('Error: '+e.message);}}
async function implode(task,el){el.classList.add('imploding');await new Promise(r=>setTimeout(r,380));task.status='done';invalidateTaskCache();await updateTask(task);loadTasksScreen();}
async function reorder(task,dir){const g=S.tasks.filter(t=>t.category===S.mode&&t.signal_or_noise===task.signal_or_noise&&['open','in_progress'].includes(t.status));const i=g.findIndex(t=>t.task_id===task.task_id),j=i+dir;if(j<0||j>=g.length)return;const o=g[j];['task_name','signal_or_noise','due_date','comment','tags'].forEach(k=>{const tmp=task[k];task[k]=o[k];o[k]=tmp;});showToast('Reordering…');invalidateTaskCache();await Promise.all([updateTask(task),updateTask(o)]);await loadTasksScreen();}
function setFilter(el,f){S.filter=f;document.querySelectorAll('.tasks-tab').forEach(b=>b.classList.toggle('active',b===el));clearTagFilter();renderTasks();}
window.clearTagFilter=()=>{S.activeTagFilter=null;document.getElementById('tag-filter-bar')?.classList.remove('visible');document.querySelectorAll('.task-item').forEach(i=>i.classList.remove('is-ostracized'));};
function applyTagFilter(name,silent=false){if(!silent&&S.activeTagFilter===name){clearTagFilter();return;}S.activeTagFilter=name;const bar=document.getElementById('tag-filter-bar'),lbl=document.getElementById('tag-filter-label');if(bar){bar.classList.add('visible');lbl.textContent=`· ${name}`;}document.querySelectorAll('.task-item').forEach(item=>{const t=S.tasks.find(x=>x.task_id===item.dataset.id);if(!t)return;item.classList.toggle('is-ostracized',!(t.tags?.includes(name)));});}
function applyDecay(){const now=Date.now();document.querySelectorAll('.task-item.noise').forEach(item=>{const t=S.tasks.find(x=>x.task_id===item.dataset.id);if(!t?.created_date)return;const age=now-new Date(t.created_date).getTime();item.classList.remove('noise-aged','noise-decayed');if(age>DECAY_BLOCK)item.classList.add('noise-decayed');else if(age>DECAY_WARN)item.classList.add('noise-aged');});}
function checkDecay(){if(document.getElementById('decay-overlay').classList.contains('active'))return;const now=Date.now();const t=S.tasks.find(x=>x.signal_or_noise==='noise'&&['open','in_progress'].includes(x.status)&&x.created_date&&(now-new Date(x.created_date).getTime())>DECAY_BLOCK);if(!t)return;S.decayTaskId=t.task_id;document.getElementById('decay-task-name').textContent=t.task_name;document.getElementById('decay-task-days').textContent=daysAgo(t.created_date)+' days open';document.getElementById('decay-overlay').classList.add('active');}
window.archiveDecayed=async()=>{const reason=document.getElementById('decay-reason').value.trim();if(!reason){document.getElementById('decay-reason').style.borderColor='var(--danger)';return;}const t=S.tasks.find(x=>x.task_id===S.decayTaskId);if(t){t.status='ignored';t.reason=reason;await updateTask(t);}document.getElementById('decay-overlay').classList.remove('active');document.getElementById('decay-reason').value='';await loadTasksScreen();};
window.keepDecayed=()=>{const reason=document.getElementById('decay-reason').value.trim();const t=S.tasks.find(x=>x.task_id===S.decayTaskId);if(t&&reason){t.comment=(t.comment?t.comment+'\n':'')+`[kept ${new Date().toLocaleDateString()}]: ${reason}`;updateTask(t).catch(()=>{});}document.getElementById('decay-overlay').classList.remove('active');document.getElementById('decay-reason').value='';};

// ── CAPTURE ──────────────────────────────
document.querySelectorAll('#cap-sn .sn-btn').forEach(btn=>btn.addEventListener('click',()=>{S.capSN=btn.dataset.val;document.querySelectorAll('#cap-sn .sn-btn').forEach(b=>{b.className='sn-btn'+(b.dataset.val===S.capSN?(S.capSN==='signal'?' sig-on':' noi-on'):'');});triggerFlash(btn.dataset.val);}));
function toggleCtx(){S.ctxOpen=!S.ctxOpen;document.getElementById('ctx-area').classList.toggle('open',S.ctxOpen);document.getElementById('ctx-toggle').textContent=(S.ctxOpen?'− ':'+ ')+'add context';}
async function submitCapture(){const name=document.getElementById('cap-text').value.trim();if(!name){document.getElementById('cap-text').focus();return;}const btn=document.getElementById('cap-btn');btn.innerHTML='<div class="spinner"></div>';btn.disabled=true;try{await appendTask({task_name:name,category:S.mode,signal_or_noise:S.capSN||'signal',due_date:document.getElementById('cap-due').value||'',comment:document.getElementById('ctx-area').value.trim(),tags:[...S.capTags],status:'open'});invalidateTaskCache();if(S._promotingNoteId){try{const notes=await getCachedNotes(true);const pn=notes.find(n=>n.note_id===S._promotingNoteId);if(pn){pn.status='promoted';pn.promoted_to_task_id=arguments[0]||'';await updateNote(pn);invalidateNoteCache();}}catch(_){}S._promotingNoteId=null;S._promotingNoteText=null;}document.getElementById('cap-text').value='';document.getElementById('cap-due').value='';document.getElementById('ctx-area').value='';document.getElementById('ctx-area').classList.remove('open');document.getElementById('ctx-toggle').textContent='+ add context';S.ctxOpen=false;S.capSN='signal';S.capTags=[];document.querySelectorAll('#cap-sn .sn-btn').forEach(b=>{b.className='sn-btn'+(b.dataset.val==='signal'?' sig-on':'');});renderCapTags();btn.textContent='✓ Captured';showToast('Signal captured');loadStats();setTimeout(()=>{btn.textContent='Capture task';btn.disabled=false;},1500);}catch(e){btn.textContent='Capture task';btn.disabled=false;showToast('Error: '+e.message);}}

// ── NOTES ──────────────────────────────
async function readNotes(){const r=await sf(`${SHEETS}/${S.spreadsheetId}/values/Notes!A2:F`);return(r.values||[]).map((r,i)=>({note_id:r[0]||'',text:r[1]||'',category:r[2]||'personal',status:r[3]||'active',created_date:r[4]||'',promoted_to_task_id:r[5]||'',_row:i})).filter(n=>n.status==='active');}
async function getCachedNotes(force=false){if(!force&&S.notes.length&&Date.now()-S._notesCacheTime<NOTE_CACHE_TTL)return S.notes;S.notes=await readNotes();S._notesCacheTime=Date.now();return S.notes;}
function invalidateNoteCache(){S._notesCacheTime=0;S.notes=[];}
async function appendNote(n){n.note_id='note_'+Date.now()+'_'+Math.random().toString(36).slice(2,7);n.created_date=todayStr();n.status='active';n.promoted_to_task_id='';await sf(`${SHEETS}/${S.spreadsheetId}/values/Notes!A:F:append?valueInputOption=RAW&insertDataOption=INSERT_ROWS`,{method:'POST',body:JSON.stringify({values:[[n.note_id,n.text,n.category,n.status,n.created_date,n.promoted_to_task_id]]})});}
async function updateNote(n){const row=n._row+2;await sf(`${SHEETS}/${S.spreadsheetId}/values/Notes!A${row}:F${row}?valueInputOption=RAW`,{method:'PUT',body:JSON.stringify({values:[[n.note_id,n.text,n.category,n.status,n.created_date,n.promoted_to_task_id]]})});}
function setCaptureMode(mode){S.captureMode=mode;document.querySelectorAll('.cap-mode-btn').forEach(b=>b.classList.toggle('active',b.dataset.cmode===mode));const taskFields=document.getElementById('task-form-fields');const noteForm=document.getElementById('note-form');const notesList=document.getElementById('notes-list');const btn=document.getElementById('cap-btn');if(mode==='task'){taskFields.style.display='';noteForm.style.display='none';notesList.style.display='none';btn.textContent=S._promotingNoteId?'Capture task (from note)':'Capture task';btn.onclick=submitCapture;updateNudge();}else{taskFields.style.display='none';noteForm.style.display='';notesList.style.display='';btn.textContent='Save note';btn.onclick=submitNote;updateNoteNudge();loadNotesList();}}
function updateNoteNudge(){const e=document.getElementById('note-nudge');if(e)e.textContent=NOTE_NUDGES[Math.floor(Math.random()*NOTE_NUDGES.length)];}
async function submitNote(){const text=document.getElementById('note-text').value.trim();if(!text){document.getElementById('note-text').focus();return;}const btn=document.getElementById('cap-btn');btn.innerHTML='<div class="spinner"></div>';btn.disabled=true;try{await appendNote({text:text,category:S.mode});invalidateNoteCache();document.getElementById('note-text').value='';btn.textContent='✓ Saved';showToast('Note saved');await loadNotesList();setTimeout(()=>{btn.textContent='Save note';btn.disabled=false;},1500);}catch(e){btn.textContent='Save note';btn.disabled=false;showToast('Error: '+e.message);}}
async function loadNotesList(){const list=document.getElementById('notes-list');if(!list||S.captureMode!=='note')return;list.innerHTML='<div class="loading-text">Loading…</div>';try{const notes=await getCachedNotes();const filtered=notes.filter(n=>n.category===S.mode);list.innerHTML='';if(!filtered.length){list.innerHTML='<div class="note-empty">No notes yet. Jot down an idea.</div>';return;}const label=div('notes-section-label');label.textContent='Your notes';list.appendChild(label);const shown=S.showAllNotes?filtered:filtered.slice(0,10);shown.sort((a,b)=>b.created_date.localeCompare(a.created_date)||(b.note_id.localeCompare(a.note_id)));shown.forEach(n=>{const item=div('note-item');item.dataset.nid=n.note_id;item.innerHTML=`<div class="note-text">${esc(n.text)}</div><div class="note-meta"><span>${fmtDate(n.created_date)||n.created_date}</span><div class="note-actions"><button class="note-action-btn note-promote-btn">↑ promote</button><button class="note-action-btn note-archive-btn">✕ archive</button><button class="note-action-btn" style="border-color:var(--basalt-2);color:var(--smoke)">✎ edit</button></div></div><div class="note-edit-wrap"><textarea class="note-edit-textarea" rows="3">${esc(n.text)}</textarea><div class="note-edit-actions"><button class="note-edit-cancel">Cancel</button><button class="note-edit-save">Save</button></div></div>`;item.querySelector('.note-promote-btn').addEventListener('click',()=>promoteNote(n));item.querySelector('.note-archive-btn').addEventListener('click',()=>archiveNote(n));item.querySelector('.note-action-btn:last-child').addEventListener('click',()=>editNoteInline(item));item.querySelector('.note-edit-cancel').addEventListener('click',()=>{item.classList.remove('editing');});item.querySelector('.note-edit-save').addEventListener('click',()=>saveNoteEdit(n,item));list.appendChild(item);});if(!S.showAllNotes&&filtered.length>10){const more=div('');more.style.cssText='text-align:center;padding:8px;font-size:11px;font-family:var(--mono);color:var(--smoke);cursor:pointer';more.textContent=`+ ${filtered.length-10} more notes`;more.addEventListener('click',()=>{S.showAllNotes=true;loadNotesList();});list.appendChild(more);}}catch(e){list.innerHTML=`<div class="note-empty">Error loading notes: ${e.message}</div>`;}}
function promoteNote(note){S._promotingNoteId=note.note_id;S._promotingNoteText=note.text;setCaptureMode('task');document.getElementById('cap-text').value=note.text;document.getElementById('cap-text').focus();const btn=document.getElementById('cap-btn');btn.textContent='Capture task (from note)';showToast('Fill in details and capture as task');}
async function archiveNote(note){note.status='archived';showToast('Archiving…');try{invalidateNoteCache();await updateNote(note);await loadNotesList();showToast('Note archived');}catch(e){showToast('Error: '+e.message);}}
function editNoteInline(item){document.querySelectorAll('.note-item.editing').forEach(i=>i.classList.remove('editing'));item.classList.add('editing');const ta=item.querySelector('.note-edit-textarea');ta.focus();ta.setSelectionRange(ta.value.length,ta.value.length);}
async function saveNoteEdit(note,item){const ta=item.querySelector('.note-edit-textarea');const newText=ta.value.trim();if(!newText){showToast('Note cannot be empty');return;}note.text=newText;showToast('Saving…');try{invalidateNoteCache();await updateNote(note);await loadNotesList();showToast('Note updated');}catch(e){showToast('Error: '+e.message);}}

// ── RITUAL ──────────────────────────────
function loadRitual(){setPhase(S.phase||(new Date().getHours()>=16?'evening':'morning'));}
window.setPhase=async function(phase){S.phase=phase;document.getElementById('rpt-morning').classList.toggle('active',phase==='morning');document.getElementById('rpt-evening').classList.toggle('active',phase==='evening');const app=document.getElementById('app');app.classList.remove('morning','evening');app.classList.add(phase);const now=new Date();document.getElementById('ritual-time').textContent=now.toLocaleDateString('en-GB',{weekday:'short',day:'numeric',month:'short'})+' · '+now.toLocaleTimeString('en-GB',{hour:'2-digit',minute:'2-digit'});const pill=document.getElementById('ritual-pill');if(phase==='morning'){pill.textContent='Morning open';pill.className='phase-pill morning';document.getElementById('ritual-title').textContent='Good morning.';document.getElementById('ritual-sub').textContent='Set your focus. Everything else can wait.';document.getElementById('ritual-cta').textContent='Start the day';buildMorning();}else{pill.textContent='Evening close';pill.className='phase-pill evening';document.getElementById('ritual-title').textContent='Time to close the day.';document.getElementById('ritual-sub').textContent='Review what happened. Clear the slate.';document.getElementById('ritual-cta').textContent='Close the day';buildEvening();}};
async function buildMorning(){const body=document.getElementById('ritual-body');body.innerHTML='';if(S.ignition.personal||S.ignition.work){const s=div('');s.innerHTML=`<div class="ritual-section-label">Today's focus signals</div><div class="ign-focus-cards">${S.ignition.personal?`<div class="ign-focus-card p"><div class="ign-focus-type">Personal</div><div class="ign-focus-text">${esc(S.ignition.personal)}</div></div>`:''} ${S.ignition.work?`<div class="ign-focus-card w"><div class="ign-focus-type">Work</div><div class="ign-focus-text">${esc(S.ignition.work)}</div></div>`:''}</div>`;body.appendChild(s);}const fc=div('');fc.innerHTML=`<div class="ritual-section-label">Primary signal for today</div><div class="focus-card"><div class="focus-pill-label">One signal</div><input class="focus-input" id="morning-focus" placeholder="The one task that makes today count…" type="text"><div class="focus-hint-text">One signal. Not two.</div></div>`;body.appendChild(fc);try{const tasks=await getCachedTasks();S.tasks=tasks;const co=tasks.filter(t=>t.category===S.mode&&['open','in_progress'].includes(t.status)).slice(0,6);if(co.length){const s=div('');s.innerHTML='<div class="ritual-section-label">Carried over — tap to act</div>';const list=div('');list.style.cssText='display:flex;flex-direction:column;gap:6px';co.forEach(t=>{const item=div(`co-item ${t.signal_or_noise}`);item.innerHTML=`<div class="co-check"><span class="co-check-tick">✓</span></div><div style="flex:1"><div class="co-name">${esc(t.task_name)}</div><div class="co-meta">${t.signal_or_noise} · ${daysAgo(t.created_date)}d open</div></div><select class="res-select" style="flex-shrink:0" data-id="${t.task_id}"><option value="open">keep</option><option value="done">done</option><option value="delegated">delegate</option><option value="ignored">ignore</option></select>`;const sel=item.querySelector('select');sel.addEventListener('change',async()=>{if(sel.value!=='open'){t.status=sel.value;showToast('Updating…');try{await updateTask(t);item.style.opacity='.3';item.style.pointerEvents='none';showToast('Updated');}catch(e){showToast('Error: '+e.message);}}});list.appendChild(item);});s.appendChild(list);body.appendChild(s);}}catch(_){}}
async function buildEvening(){const body=document.getElementById('ritual-body');body.innerHTML='<div class="loading-text">Loading…</div>';try{const tasks=await getCachedTasks();S.tasks=tasks;const cat=tasks.filter(t=>t.category===S.mode);const today=todayStr();const done=cat.filter(t=>t.status==='done'&&t.closed_date===today),open=cat.filter(t=>['open','in_progress'].includes(t.status));const sd=done.filter(t=>t.signal_or_noise==='signal').length,nd=done.filter(t=>t.signal_or_noise==='noise').length;body.innerHTML='';const fp=ls('focus_ign_p'),fw=ls('focus_ign_w'),focusText=S.mode==='work'?fw:fp;if(focusText){const fc=div('');const achieved=done.some(t=>t.task_name.toLowerCase().includes(focusText.toLowerCase()));fc.innerHTML=`<div class="ritual-section-label">Morning focus check</div><div style="padding:12px;border-radius:10px;border:0.5px solid ${achieved?'rgba(34,197,94,.3)':'rgba(239,68,68,.3)'};background:${achieved?'rgba(34,197,94,.06)':'rgba(239,68,68,.06)'}"><div style="font-family:var(--serif);font-style:italic;font-size:14px;color:#fff;margin-bottom:6px">"${esc(focusText)}"</div><div style="font-size:12px;color:${achieved?'var(--signal)':'var(--danger)'}">${achieved?'Achieved — you followed through.':'Not yet completed. Still time to act, or carry it forward.'}</div></div>`;body.appendChild(fc);}const stats=div('');stats.innerHTML=`<div class="ritual-section-label">Today at a glance</div><div class="ev-stats"><div class="ev-stat s"><div class="ev-stat-num">${sd}</div><div class="ev-stat-label">signals closed</div></div><div class="ev-stat n"><div class="ev-stat-num">${nd}</div><div class="ev-stat-label">noise closed</div></div><div class="ev-stat r"><div class="ev-stat-num">${fmtRatio(sd,nd)}</div><div class="ev-stat-label">ratio</div></div></div>`;body.appendChild(stats);if(sd>0){const win=div('win-strip');win.innerHTML=`<div class="win-ico">◎</div><div class="win-text"><strong>Progress made.</strong> ${sd} signal${sd>1?'s':''} closed today.</div>`;body.appendChild(win);}if(open.length){const undone=div('');undone.innerHTML='<div class="ritual-section-label">Still open — decide now</div>';const list=div('');list.id='ev-undone';list.style.cssText='display:flex;flex-direction:column;gap:6px';open.forEach(t=>{const item=div(`res-item ${t.signal_or_noise}`);item.dataset.id=t.task_id;item.innerHTML=`<div class="res-top"><div class="res-name">${esc(t.task_name)}</div></div><div class="res-bottom"><div class="res-tags"><span class="tag ${t.signal_or_noise==='signal'?'sig':'noi'}">${t.signal_or_noise}</span><span class="tag muted">${daysAgo(t.created_date)}d</span></div><select class="res-select" data-id="${t.task_id}"><option value="open">carry over</option><option value="delegated">delegate</option><option value="ignored">ignore</option></select></div><div class="reason-wrap" id="rw-${t.task_id}"><div class="reason-inner"><div class="reason-label">Architect's Decision</div><textarea class="reason-input" id="rt-${t.task_id}" rows="2" placeholder=""></textarea></div></div>`;const sel=item.querySelector('select');sel.addEventListener('change',()=>{const val=sel.value,wrap=document.getElementById(`rw-${t.task_id}`),ta=document.getElementById(`rt-${t.task_id}`);item.classList.remove('delegated','ignored');sel.classList.remove('delegated','ignored');wrap.classList.remove('open');if(val==='delegated'||val==='ignored'){item.classList.add(val);sel.classList.add(val);wrap.classList.add('open');ta.placeholder=val==='delegated'?'To whom, and why?':'Why not worth your attention?';setTimeout(()=>ta.focus(),300);}});list.appendChild(item);});undone.appendChild(list);body.appendChild(undone);}}catch(err){document.getElementById('ritual-body').innerHTML=`<div class="empty-state"><strong>Error</strong>${err.message}</div>`;}}
async function onRitualCTA(){const phase=S.phase||(new Date().getHours()>=16?'evening':'morning');if(phase==='evening'){const updates=[];document.querySelectorAll('#ev-undone select').forEach(sel=>{const t=S.tasks.find(x=>x.task_id===sel.dataset.id);if(!t)return;t.status=sel.value;const reason=document.getElementById(`rt-${sel.dataset.id}`)?.value.trim();if(reason)t.reason=reason;updates.push(updateTask(t));});if(updates.length)await Promise.all(updates);}showScreen('tasks');}

// ── REVIEW ──────────────────────────────
async function loadReview(){const now=new Date();document.getElementById('review-date').textContent=now.toLocaleDateString('en-GB',{weekday:'short',day:'numeric',month:'short'})+` · week ${weekNum()}`;try{const tasks=await getCachedTasks();S.tasks=tasks;const cat=tasks.filter(t=>t.category===S.mode);const dow=now.getDay(),sow=new Date(now);sow.setDate(now.getDate()-(dow===0?6:dow-1));sow.setHours(0,0,0,0);const sowStr=sow.toISOString().split('T')[0];const weekCat=cat.filter(t=>(t.created_date&&t.created_date>=sowStr)||(t.closed_date&&t.closed_date>=sowStr));const sd=weekCat.filter(t=>t.signal_or_noise==='signal'&&t.status==='done').length;const nd=weekCat.filter(t=>t.signal_or_noise==='noise'&&t.status==='done').length;const ign=weekCat.filter(t=>t.status==='ignored').length,del=weekCat.filter(t=>t.status==='delegated').length;const closed=weekCat.filter(t=>['done','delegated','ignored'].includes(t.status)).length;const comp=weekCat.length?Math.round((closed/weekCat.length)*100):0;const sigT=weekCat.filter(t=>t.signal_or_noise==='signal').length;const fs=sigT?Math.round((sd/sigT)*100):null;document.getElementById('fr-score').textContent=fs!==null?fs+'%':'—';document.getElementById('fr-score-sub').textContent=fs!==null?`${sd} of ${sigT} signals finished`:'No signal tasks yet';const narr=document.getElementById('debrief-narrative');if(narr){if(fs!==null){const lvl=fs>=80?'high':fs>=50?'moderate':'low';const noiseCarried=cat.filter(t=>t.signal_or_noise==='noise'&&t.status==='open').length;let txt=`Architecture Status: ${lvl==='high'?'Stable':'Recalibrating'}. You resolved ${sd} signal${sd!==1?'s':''} with ${fs}% intentionality this week.`;if(ign>0)txt+=` You consciously released ${ign} task${ign!==1?'s':''} — that is data, not failure.`;if(noiseCarried>3)txt+=` ${noiseCarried} noise tasks persist. Consider: what is the cost of carrying them?`;narr.innerHTML=txt;narr.style.display='block';}else{narr.style.display='none';}}document.getElementById('fr-sd').textContent=sd;document.getElementById('fr-nd').textContent=nd;document.getElementById('fr-comp').textContent=comp+'%';document.getElementById('fr-ign').textContent=ign;document.getElementById('fr-del').textContent=del;document.getElementById('fr-str').textContent=streak(tasks);const nt=Math.max(nd+del+ign,1);nb('nb-done',nd,nt);nb('nb-del',del,nt);nb('nb-ign',ign,nt);nb('nb-carry',weekCat.filter(t=>t.signal_or_noise==='noise'&&t.status==='open').length,Math.max(nt+1,1));buildAging('fr-aging-sig',cat.filter(t=>t.signal_or_noise==='signal'&&['open','in_progress'].includes(t.status)&&daysAgo(t.created_date)>=5),'signal');buildAging('fr-aging-noi',cat.filter(t=>t.signal_or_noise==='noise'&&['open','in_progress'].includes(t.status)&&daysAgo(t.created_date)>=7),'noise');drawRadar(tasks);buildTagReview(weekCat);buildCompare(tasks);S._weekSignalsCaptured=weekCat.filter(t=>t.signal_or_noise==='signal').length;S._weekNoiseCaptured=weekCat.filter(t=>t.signal_or_noise==='noise').length;}catch(e){console.error(e);}}
function frTab(el,p){document.querySelectorAll('.fr-tab').forEach(b=>b.classList.toggle('active',b===el));document.querySelectorAll('.fr-panel').forEach(x=>x.classList.toggle('active',x.id===`fr-${p}`));}
function nb(id,val,total){const p=Math.round((val/total)*100);document.getElementById(id).style.width=p+'%';document.getElementById(id+'-val').textContent=val;}
function buildAging(cid,tasks,type){const c=document.getElementById(cid);if(!c)return;if(!tasks.length){c.innerHTML=`<div class="empty-state"><strong>All clear</strong>No aging ${type} tasks.</div>`;return;}c.innerHTML='';tasks.forEach(t=>{const item=div(`aged-item ${type}`);const opts=type==='signal'?'<option value="">keep open</option><option value="break">break into steps</option><option value="delegated">delegate</option><option value="ignored">ignore</option>':'<option value="">carry over</option><option value="delegated">delegate</option><option value="ignored">ignore</option>';item.innerHTML=`<div class="aged-name">${esc(t.task_name)}</div><div class="aged-row"><div class="aged-tags"><span class="tag ${type==='signal'?'sig':'noi'}">${type}</span><span class="tag muted">${daysAgo(t.created_date)}d</span></div><select class="aged-select" data-taskid="${t.task_id}">${opts}</select></div>`;const sel=item.querySelector('select');sel.addEventListener('change',async()=>{const val=sel.value;if(!val)return;if(val==='break'){showToast('Tip: break this signal into smaller tasks in Capture');sel.value='';return;}t.status=val;t.reason=`Decided during review (${daysAgo(t.created_date)}d aging)`;showToast(`Task ${val}…`);try{await updateTask(t);item.style.opacity='.3';item.style.pointerEvents='none';showToast('Updated');}catch(e){showToast('Error: '+e.message);}});c.appendChild(item);});}
function buildTagReview(tasks){const tc={},td={};tasks.forEach(t=>{(t.tags||[]).forEach(n=>{tc[n]=(tc[n]||0)+1;if(t.status==='done')td[n]=(td[n]||0)+1;});});const max=Math.max(...Object.values(tc),1),sorted=Object.entries(tc).sort((a,b)=>b[1]-a[1]);const chart=document.getElementById('fr-tag-chart'),bd=document.getElementById('fr-tag-bd');if(!chart||!bd)return;chart.innerHTML='';bd.innerHTML='';if(!sorted.length){chart.innerHTML='<div class="empty-state"><strong>No tag data</strong>Tag tasks when capturing.</div>';return;}sorted.forEach(([n,cnt])=>{const t=S.tags.find(x=>x.name===n),c=t?t.color:'#888',pct=Math.round((cnt/max)*100);const r1=div('tag-review-item');r1.innerHTML=`<div class="tag-review-name">${esc(n)}</div><div class="tag-review-track"><div class="tag-review-fill" style="width:${pct}%;background:${c}"></div></div><div class="tag-review-count">${cnt}</div>`;chart.appendChild(r1);const done=td[n]||0,r2=div('tag-review-item');r2.innerHTML=`<div class="tag-review-name" style="display:flex;align-items:center;gap:5px"><span style="width:7px;height:7px;border-radius:50%;background:${c};display:inline-block"></span>${esc(n)}</div><div class="tag-review-track"><div class="tag-review-fill" style="width:${Math.round((done/cnt)*100)}%;background:${c}80"></div></div><div class="tag-review-count">${done}/${cnt}</div>`;bd.appendChild(r2);});}
function buildCompare(all){const grid=document.getElementById('fr-compare-grid');if(!grid)return;const cat=all.filter(t=>t.category===S.mode),now=new Date(),dow=now.getDay();const sow=new Date(now);sow.setDate(now.getDate()-(dow===0?6:dow-1));sow.setHours(0,0,0,0);const solw=new Date(sow);solw.setDate(sow.getDate()-7);const eolw=new Date(sow);eolw.setDate(sow.getDate()-1);const tw=cat.filter(t=>t.created_date&&new Date(t.created_date)>=sow),lw=cat.filter(t=>t.created_date&&new Date(t.created_date)>=solw&&new Date(t.created_date)<=eolw);const ws=t=>{const sd=t.filter(x=>x.signal_or_noise==='signal'&&x.status==='done').length,nd=t.filter(x=>x.signal_or_noise==='noise'&&x.status==='done').length,cl=t.filter(x=>['done','delegated','ignored'].includes(x.status)).length;return{sd,nd,ratio:fmtRatio(sd,nd),comp:t.length?Math.round((cl/t.length)*100)+'%':'0%',total:t.length};};const t=ws(tw),l=ws(lw);grid.innerHTML=`<div class="compare-table"><div class="compare-row header"><div class="compare-cell"></div><div class="compare-cell">this week</div><div class="compare-cell">last week</div></div><div class="compare-row"><div class="compare-cell lbl">signals done</div><div class="compare-cell val ${t.sd>=l.sd?'up':'dn'}">${t.sd}</div><div class="compare-cell val">${l.sd}</div></div><div class="compare-row"><div class="compare-cell lbl">noise done</div><div class="compare-cell val">${t.nd}</div><div class="compare-cell val">${l.nd}</div></div><div class="compare-row"><div class="compare-cell lbl">ratio</div><div class="compare-cell val accent">${t.ratio}</div><div class="compare-cell val">${l.ratio}</div></div><div class="compare-row"><div class="compare-cell lbl">completion</div><div class="compare-cell val">${t.comp}</div><div class="compare-cell val">${l.comp}</div></div><div class="compare-row"><div class="compare-cell lbl">captured</div><div class="compare-cell val">${t.total}</div><div class="compare-cell val">${l.total}</div></div></div>`;}
function drawRadar(tasks){const canvas=document.getElementById('radar-canvas');if(!canvas)return;const ctx=canvas.getContext('2d'),W=canvas.width,H=canvas.height,CX=W/2,CY=H/2+6,MAXR=Math.min(W,H)*0.34;ctx.clearRect(0,0,W,H);const td=S.tags.map(tag=>{const tt=tasks.filter(t=>t.category===S.mode&&t.tags?.includes(tag.name));return{name:tag.name,color:tag.color,sDone:tt.filter(t=>t.signal_or_noise==='signal'&&t.status==='done').length,nDone:tt.filter(t=>t.signal_or_noise==='noise'&&t.status==='done').length,sOpen:tt.filter(t=>t.signal_or_noise==='signal'&&['open','in_progress'].includes(t.status)).length,nOpen:tt.filter(t=>t.signal_or_noise==='noise'&&['open','in_progress'].includes(t.status)).length,total:tt.length};}).filter(d=>d.total>0);if(!td.length){ctx.fillStyle='rgba(64,64,65,0.5)';ctx.font='11px DM Mono,monospace';ctx.textAlign='center';ctx.fillText('No tagged tasks yet',CX,CY);document.getElementById('radar-legend').innerHTML='';return;}const N=td.length,step=(Math.PI*2)/N,maxC=Math.max(...td.map(d=>d.total),1);[0.33,0.66,1.0].forEach(r=>{ctx.beginPath();ctx.arc(CX,CY,MAXR*r,0,Math.PI*2);ctx.strokeStyle='rgba(255,255,255,0.05)';ctx.lineWidth=0.5;ctx.stroke();});ctx.font='7px DM Mono,monospace';ctx.textAlign='center';ctx.fillStyle='rgba(34,197,94,0.3)';ctx.fillText('SIGNAL',CX,CY-MAXR*0.18);ctx.fillStyle='rgba(212,175,55,0.28)';ctx.fillText('NOISE',CX,CY-MAXR*0.82);td.forEach((tag,i)=>{const start=i*step-Math.PI/2,end=(i+1)*step-Math.PI/2,r=Math.max((tag.total/maxC)*MAXR,10);ctx.beginPath();ctx.moveTo(CX,CY);ctx.arc(CX,CY,r,start,end);ctx.closePath();ctx.fillStyle=tag.color+'14';ctx.strokeStyle=tag.color+'35';ctx.lineWidth=0.5;ctx.fill();ctx.stroke();const sc=tag.sDone+tag.sOpen;if(sc>0){const sr=(sc/tag.total)*r*0.42;ctx.beginPath();ctx.moveTo(CX,CY);ctx.arc(CX,CY,Math.max(sr,4),start,end);ctx.closePath();ctx.fillStyle=`rgba(34,197,94,${tag.sDone>0?0.45:0.18})`;ctx.fill();}const nc=tag.nDone+tag.nOpen;if(nc>0){ctx.beginPath();ctx.arc(CX,CY,r,start,end);ctx.arc(CX,CY,r*0.55,end,start,true);ctx.closePath();ctx.fillStyle=`rgba(212,175,55,${tag.nDone>0?0.38:0.14})`;ctx.fill();}ctx.beginPath();ctx.moveTo(CX,CY);ctx.lineTo(CX+Math.cos(start)*(r+10),CY+Math.sin(start)*(r+10));ctx.strokeStyle='rgba(255,255,255,0.07)';ctx.lineWidth=0.5;ctx.stroke();const mid=start+step/2,lr=r+16,lx=CX+Math.cos(mid)*lr,ly=CY+Math.sin(mid)*lr;ctx.fillStyle=tag.color;ctx.font='8px DM Mono,monospace';ctx.textAlign=Math.cos(mid)>0.15?'left':Math.cos(mid)<-0.15?'right':'center';ctx.fillText(tag.name.length>10?tag.name.slice(0,9)+'…':tag.name,lx,ly+3);});ctx.beginPath();ctx.arc(CX,CY,3.5,0,Math.PI*2);ctx.fillStyle='rgba(212,175,55,0.8)';ctx.fill();const leg=document.getElementById('radar-legend');leg.innerHTML='';td.forEach(tag=>{const item=div('radar-legend-item');item.innerHTML=`<span class="radar-legend-dot" style="background:${tag.color}"></span><span class="radar-legend-name">${esc(tag.name)}</span><span class="radar-legend-count">${tag.total}</span>`;leg.appendChild(item);});}
async function closeWeek(){const btn=document.getElementById('fr-close-btn');btn.textContent='Saving…';btn.disabled=true;try{const sc=S._weekSignalsCaptured||0,nc=S._weekNoiseCaptured||0;await sf(`${SHEETS}/${S.spreadsheetId}/values/Weekly Review!A:N:append?valueInputOption=RAW&insertDataOption=INSERT_ROWS`,{method:'POST',body:JSON.stringify({values:[[weekNum(),new Date().getFullYear(),sc,parseInt(document.getElementById('fr-sd').textContent)||0,nc,parseInt(document.getElementById('fr-nd').textContent)||0,parseInt(document.getElementById('fr-ign').textContent)||0,parseInt(document.getElementById('fr-del').textContent)||0,document.getElementById('fr-comp').textContent,document.getElementById('fr-score').textContent,'',document.getElementById('ref-ratio')?.value||'',document.getElementById('ref-hard')?.value||'',document.getElementById('ref-next')?.value||'']]})});btn.textContent='✓ Week closed';markFridayReviewDone();setTimeout(()=>{btn.textContent='Close week';btn.disabled=false;showScreen('capture');},1500);}catch(e){btn.textContent='Close week';btn.disabled=false;showToast(e.message);}}
function streak(tasks){let s=0;const now=new Date();for(let i=0;i<30;i++){const d=new Date(now);d.setDate(now.getDate()-i);const ds=d.toISOString().split('T')[0];if(tasks.some(t=>t.closed_date===ds&&t.status==='done'))s++;else if(i>0)break;}return s;}

// ── SETTINGS ──────────────────────────────
function loadSettings(){updateSettingsFocus();renderTagManage();renderColorPicker();document.getElementById('s-sheet-id').textContent=S.spreadsheetId||'—';}
function updateSettingsFocus(){const p=document.getElementById('s-personal-focus'),w=document.getElementById('s-work-focus');if(p)p.textContent=S.ignition.personal||'—';if(w)w.textContent=S.ignition.work||'—';}
function renderTagManage(){const list=document.getElementById('s-tag-list');if(!list)return;list.innerHTML='';S.tags.forEach((tag,i)=>{const item=div('tag-manage-item');item.innerHTML=`<div class="tag-color-dot" style="background:${tag.color}"></div><input class="tag-manage-name" value="${esc(tag.name)}" data-i="${i}"><button class="tag-delete-btn" data-i="${i}">×</button>`;item.querySelector('input').addEventListener('input',e=>{S.tags[+e.target.dataset.i].name=e.target.value;});item.querySelector('button').addEventListener('click',e=>{S.tags.splice(+e.target.dataset.i,1);renderTagManage();});list.appendChild(item);});}
function renderColorPicker(){const row=document.getElementById('s-colors');if(!row)return;row.innerHTML='<div style="font-size:10px;color:var(--smoke-2);margin-bottom:4px;width:100%;letter-spacing:.06em;text-transform:uppercase">Color for new tag</div>';TAG_PALETTE.forEach(c=>{const s=div('color-swatch'+(c===S.newTagColor?' selected':''));s.style.background=c;s.addEventListener('click',()=>{S.newTagColor=c;renderColorPicker();});row.appendChild(s);});}
function addTag(){const inp=document.getElementById('s-new-tag'),name=inp.value.trim();if(!name||S.tags.find(t=>t.name.toLowerCase()===name.toLowerCase()))return;S.tags.push({name,color:S.newTagColor});inp.value='';renderTagManage();renderCapTags();}
async function saveTags(){const btn=document.getElementById('s-save-tags');btn.textContent='Saving…';btn.disabled=true;try{await sf(`${SHEETS}/${S.spreadsheetId}/values/Tags!A1:B?valueInputOption=RAW`,{method:'PUT',body:JSON.stringify({values:[['tag_name','color'],...S.tags.map(t=>[t.name,t.color])]})});btn.textContent='✓ Saved';renderCapTags();setTimeout(()=>{btn.textContent='Save tags';btn.disabled=false;},1500);}catch(e){btn.textContent='Save tags';btn.disabled=false;showToast(e.message);}}
function openSheet(){chrome.tabs.create({url:`https://docs.google.com/spreadsheets/d/${S.spreadsheetId}`});}
function showChangeSheet(){document.getElementById('change-sheet-wrap').style.display='block';document.getElementById('change-sheet-btn').style.display='none';document.getElementById('change-sheet-input').value='';document.getElementById('change-sheet-input').focus();}
function cancelChangeSheet(){document.getElementById('change-sheet-wrap').style.display='none';document.getElementById('change-sheet-btn').style.display='block';}
async function applyChangeSheet(){let v=document.getElementById('change-sheet-input').value.trim();if(!v){showToast('Paste a Sheet ID or URL');return;}const m=v.match(/\/spreadsheets\/d\/([a-zA-Z0-9_-]+)/);if(m)v=m[1];lss('focus_spreadsheet_id',v);S.spreadsheetId=v;cancelChangeSheet();document.getElementById('s-sheet-id').textContent=v;showToast('Reconnecting…');try{await loadTags();await loadStats();showToast('Connected! '+S.tasks.length+' tasks loaded');}catch(e){showToast('Error: '+e.message);}}
function signOut(){if(!confirm('Sign out? Your sheet is kept.'))return;chrome.storage.local.clear(()=>{window.close();});}

// ── NAV ──────────────────────────────────
function showScreen(id){document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));document.getElementById('screen-'+id).classList.add('active');document.querySelectorAll('.nav-btn').forEach(b=>b.classList.toggle('active',b.dataset.s===id));if(id==='tasks')loadTasksScreen();if(id==='capture'){loadStats();if(S.captureMode==='note'){updateNoteNudge();loadNotesList();}else{updateNudge();}}if(id==='ritual')loadRitual();if(id==='review')loadReview();if(id==='settings')loadSettings();}
function showMain(){document.getElementById('screen-login').classList.remove('active');document.getElementById('main-app').style.display='flex';checkFridayReview();}
function checkFridayReview(){const now=new Date();if(now.getDay()===5&&ls('focus_last_friday_review')!==todayStr()){setTimeout(()=>{showToast('It\'s Friday — time for your weekly review');},2000);}}
window.markFridayReviewDone=()=>{lss('focus_last_friday_review',todayStr());};

// ── MODE ──────────────────────────────────
function toggleMode(){applyMode(S.mode==='work'?'personal':'work');const active=document.querySelector('.nav-btn.active');if(active&&active.dataset.s!=='capture'){showScreen(active.dataset.s);}else{loadStats();renderCapTags();if(S.captureMode==='note')loadNotesList();}}
function applyMode(m,reload=true){S.mode=m;lss('focus_mode',m);document.getElementById('app').className=m;document.getElementById('ctx-label').textContent=m;updateNudge();if(reload)loadStats();}

// ── INTERACTIONS ──────────────────────────
function updateNudge(){const e=document.getElementById('capture-nudge');if(!e)return;const pool=NUDGES[S.mode];e.textContent=pool[Math.floor(Math.random()*pool.length)];}
function triggerFlash(type){const app=document.getElementById('app');app.classList.remove('sn-flash-signal','sn-flash-noise');void app.offsetWidth;app.classList.add(type==='signal'?'sn-flash-signal':'sn-flash-noise');setTimeout(()=>app.classList.remove('sn-flash-signal','sn-flash-noise'),600);}

// ── HELPERS ──────────────────────────────
function div(cls){const e=document.createElement('div');if(cls)e.className=cls;return e;}
function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function todayStr(){return new Date().toISOString().split('T')[0];}
function fmtRatio(s,n){if(s===0&&n===0)return'—';return`${s}:${n}`;}
function toggleTicker(){const w=document.getElementById('ticker-wrap'),b=document.getElementById('ticker-toggle');const show=w.style.display==='none';w.style.display=show?'':'none';b.textContent=show?'hide timeline':'show timeline';lss('focus_ticker_visible',show?'1':'0');}
function weekNum(){const d=new Date();d.setHours(0,0,0,0);d.setDate(d.getDate()+4-(d.getDay()||7));const y=new Date(d.getFullYear(),0,1);return Math.ceil((((d-y)/86400000)+1)/7);}
function daysAgo(s){if(!s)return 0;return Math.max(0,Math.floor((Date.now()-new Date(s).getTime())/86400000));}
function fmtDate(s){if(!s)return'';return new Date(s).toLocaleDateString('en-GB',{day:'numeric',month:'short'});}
function ls(k){return _store[k]||null;}
function lss(k,v){_store[k]=v;chrome.storage.local.set({[k]:v});}
function showToast(m){const t=document.getElementById('toast');t.textContent=m;t.classList.add('show');setTimeout(()=>t.classList.remove('show'),2200);}

